const content = $('Load Approved Only').item.json;
const integ = items[0].json;
// IDEMPOTENCY: already published
if (content.postiz_post_id) {
  return [{ json: { abort: true, content_item_id: content.id, reason: 'Idempotent skip: postiz_post_id already set' } }];
}
// STAGING isolation: block real publish unless explicitly allowed
const allowStaging = String($env.ALLOW_STAGING_PUBLISH || '').toLowerCase() === 'true';
if ((content.is_staging || content.environment === 'staging') && !allowStaging) {
  return [{ json: { abort: true, content_item_id: content.id, reason: 'Staging campaign — publish blocked (set ALLOW_STAGING_PUBLISH=true only for controlled dry posts)' } }];
}
if (!integ || !integ.postiz_integration_id || integ.is_active === false) {
  return [{
    json: {
      abort: true,
      content_item_id: content.id,
      reason: `No active Postiz integration for channel=${content.channel}`
    }
  }];
}
const scheduledTime = content.scheduled_time;
const type = scheduledTime && new Date(scheduledTime) > new Date() ? 'schedule' : 'now';
const date = scheduledTime || new Date().toISOString();
const image = content.media_url ? [{ id: 'external', path: content.media_url }] : [];
const settings = integ.postiz_settings || { __type: content.channel };
const payload = {
  type,
  date,
  shortLink: false,
  tags: [],
  posts: [{
    integration: { id: integ.postiz_integration_id },
    value: [{ content: content.draft_copy, image }],
    settings
  }]
};
return [{
  json: {
    abort: false,
    content_item_id: content.id,
    campaign_id: content.campaign_id,
    channel: content.channel,
    postiz_payload: payload
  }
}];

