const resp = items[0].json;
const ctx = $('Build Postiz Payload').item.json;
const statusCode = resp.statusCode || resp.status || 200;
// n8n may put body at root when neverError
const body = resp.body || resp;
const failed = (statusCode >= 400) || body.error || body.message === 'Unauthorized';
const postizId = body.id || body.postId || body[0]?.postId || body[0]?.id || null;
if (failed || !postizId) {
  return [{
    json: {
      ok: false,
      content_item_id: ctx.content_item_id,
      campaign_id: ctx.campaign_id,
      channel: ctx.channel,
      error: body.error || body.message || JSON.stringify(body).slice(0, 500),
      postiz_post_id: null
    }
  }];
}
return [{
  json: {
    ok: true,
    content_item_id: ctx.content_item_id,
    campaign_id: ctx.campaign_id,
    channel: ctx.channel,
    postiz_post_id: String(postizId),
    post_status: ctx.postiz_payload.type === 'schedule' ? 'scheduled' : 'live'
  }
}];

